const body = $json;
if (body.benefit_type !== 'Pipeline_audit') {
  return [{ json: { success: false, error_code: 'INVALID_INPUT', message: 'benefit_type must be Pipeline_audit' } }];
}
const leadLeakage = Number(body.answers.lead_leakage ?? body.answers.question_1 ?? 0);
const conversionGap = Number(body.answers.stage_conversion_gaps ?? body.answers.question_2 ?? 0);
const dealAging = Number(body.answers.deal_aging ?? body.answers.question_3 ?? 0);
if (![leadLeakage, conversionGap, dealAging].every(Number.isFinite)) {
  return [{ json: { success: false, error_code: 'INVALID_INPUT', message: 'lead leakage, stage conversion gaps and deal aging must be numeric' } }];
}
return [{ json: { ...body, metrics: { leadLeakage, conversionGap, dealAging } } }];

if ($json.success === false) return [{ json: $json }];
const { leadLeakage, conversionGap, dealAging } = $json.metrics;
const score = Math.max(0, Math.min(100, Math.round(100 - (leadLeakage * 0.5 + conversionGap * 0.3 + dealAging * 0.2))));
const stages = ['Discovery', 'Qualification', 'Proposal', 'Negotiation', 'Close'];
const values = [leadLeakage, conversionGap, dealAging, conversionGap + 5, leadLeakage - 5];
const bottleneck_stage = stages[values.indexOf(Math.max(...values))];
return [{ json: { ...$json, score, bottleneck_stage } }];

if ($json.success === false) return [{ json: $json }];
const recommendation_list = [
  'Implement stage-entry criteria for every opportunity.',
  'Set SLA for follow-up and stale deal remediation.',
  'Add weekly leakage and conversion dashboard reviews.'
];
return [{
  json: {
    success: true,
    benefit_type: 'Pipeline_audit',
    score: $json.score,
    summary: `Pipeline health score is ${$json.score}. Bottleneck stage: ${$json.bottleneck_stage}.`,
    recommendations: recommendation_list,
    meta: {
      execution_id: $execution.id,
      version: '1.0.0',
      benefit_version: '2026-Q1',
      pipeline_health_score: $json.score,
      bottleneck_stage: $json.bottleneck_stage
    }
  }
}];
